int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        unordered_set<long long> s; s.reserve(N*2);
        for(int i=0;i<N;i++){
            long long x; cin>>x; s.insert(x);
        }
        int best = 0;
        for(const long long &x : s){
            if(s.find(x-1) == s.end()){
                int len = 1;
                long long cur = x+1;
                while(s.find(cur) != s.end()){
                    ++len; ++cur;
                }
                if(len > best) best = len;
            }
        }
        cout << best << '\n';
    }
    return 0;
}

