import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        s = set()
        for _ in range(N):
            s.add(int(next(it)))
        best = 0
        for x in s:
            if x - 1 not in s:
                cur = x
                length = 0
                while cur in s:
                    length += 1
                    cur += 1
                if length > best:
                    best = length
        out.append(str(best))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

